"use client";

import { useState } from "react";
import {
    Settings, Store, Palette, Shield, CreditCard,
    Bell, Globe, Save, CheckCircle, Truck, Mail, Phone, MapPin
} from "lucide-react";

export default function AdminSettingsPage() {
    const [activeTab, setActiveTab] = useState("geral");
    const [saved, setSaved] = useState(false);
    const [settings, setSettings] = useState({
        storeName: "DripShop",
        storeEmail: "contato@dripshop.com.br",
        storePhone: "(11) 3333-3333",
        storeAddress: "Rua Example, 123 - S├úo Paulo, SP",
        currency: "BRL",
        language: "pt-BR",
        freeShippingValue: 199,
        shippingPrice: 15,
        shippingTime: "5-7 dias ├║teis",
        primaryColor: "#000000",
        darkMode: false,
        instagram: "",
        facebook: "",
        twitter: "",
        notifyNewOrder: true,
        notifyLowStock: true,
        notifyNewCustomer: false,
    });

    const handleSave = () => {
        setSaved(true);
        setTimeout(() => setSaved(false), 3000);
    };

    const updateSettings = (key: string, value: any) => {
        setSettings({ ...settings, [key]: value });
    };

    const tabs = [
        { id: "geral", label: "Geral", icon: Store },
        { id: "frete", label: "Frete", icon: Truck },
        { id: "aparencia", label: "Apar├¬ncia", icon: Palette },
        { id: "contato", label: "Contato", icon: Mail },
        { id: "notificacoes", label: "Notifica├º├Áes", icon: Bell },
    ];

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
                <div>
                    <h1 className="text-2xl lg:text-3xl font-bold" style={{ fontFamily: "Space Grotesk, sans-serif" }}>
                        Configura├º├Áes
                    </h1>
                    <p className="text-gray-500 text-sm mt-1">Gerencie as prefer├¬ncias da sua loja</p>
                </div>
                <button
                    onClick={handleSave}
                    className="bg-primary text-white py-2.5 px-6 rounded-xl font-medium hover:bg-primary-dark transition-colors flex items-center gap-2 shadow-lg shadow-primary/25"
                >
                    {saved ? <CheckCircle className="w-4 h-4" /> : <Save className="w-4 h-4" />}
                    {saved ? "Salvo!" : "Salvar Altera├º├Áes"}
                </button>
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                {/* Sidebar Tabs */}
                <div className="lg:w-64 space-y-1">
                    {tabs.map((tab) => {
                        const Icon = tab.icon;
                        return (
                            <button
                                key={tab.id}
                                onClick={() => setActiveTab(tab.id)}
                                className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-medium transition-all ${
                                    activeTab === tab.id
                                        ? "bg-gray-900 text-white shadow-lg"
                                        : "text-gray-500 hover:text-gray-900 hover:bg-gray-100"
                                }`}
                            >
                                <Icon className="w-5 h-5" />
                                {tab.label}
                            </button>
                        );
                    })}
                </div>

                {/* Content Area */}
                <div className="flex-1 bg-white rounded-2xl border border-gray-100 shadow-sm p-6 lg:p-8">
                    {/* Geral Tab */}
                    {activeTab === "geral" && (
                        <div className="space-y-6 animate-fade-in">
                            <h2 className="text-lg font-bold">Informa├º├Áes da Loja</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Nome da Loja</label>
                                    <input 
                                        type="text" 
                                        value={settings.storeName}
                                        onChange={(e) => updateSettings("storeName", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Moeda</label>
                                    <select 
                                        value={settings.currency}
                                        onChange={(e) => updateSettings("currency", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm"
                                    >
                                        <option value="BRL">Real (R$)</option>
                                        <option value="USD">D├│lar ($)</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Idioma Padr├úo</label>
                                    <select 
                                        value={settings.language}
                                        onChange={(e) => updateSettings("language", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm"
                                    >
                                        <option value="pt-BR">Portugu├¬s (Brasil)</option>
                                        <option value="en-US">English (US)</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Frete Tab */}
                    {activeTab === "frete" && (
                        <div className="space-y-6 animate-fade-in">
                            <h2 className="text-lg font-bold">Configura├º├Áes de Frete</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Valor para Frete Gr├ítis</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">R$</span>
                                        <input 
                                            type="number" 
                                            value={settings.freeShippingValue}
                                            onChange={(e) => updateSettings("freeShippingValue", Number(e.target.value))}
                                            className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Valor do Frete</label>
                                    <div className="relative">
                                        <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400">R$</span>
                                        <input 
                                            type="number" 
                                            value={settings.shippingPrice}
                                            onChange={(e) => updateSettings("shippingPrice", Number(e.target.value))}
                                            className="w-full pl-10 pr-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                        />
                                    </div>
                                </div>
                                <div className="md:col-span-2">
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Prazo de Entrega</label>
                                    <input 
                                        type="text" 
                                        value={settings.shippingTime}
                                        onChange={(e) => updateSettings("shippingTime", e.target.value)}
                                        placeholder="Ex: 5-7 dias ├║teis"
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Apar├¬ncia Tab */}
                    {activeTab === "aparencia" && (
                        <div className="space-y-6 animate-fade-in">
                            <h2 className="text-lg font-bold">Customiza├º├úo Visual</h2>

                            <div className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                                <div>
                                    <p className="text-sm font-medium">Modo Escuro</p>
                                    <p className="text-xs text-gray-500">Ativar tema escuro na loja</p>
                                </div>
                                <button 
                                    onClick={() => updateSettings("darkMode", !settings.darkMode)}
                                    className={`w-12 h-6 rounded-full relative transition-colors ${settings.darkMode ? 'bg-primary' : 'bg-gray-300'}`}
                                >
                                    <span className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${settings.darkMode ? 'right-1' : 'left-1'}`} />
                                </button>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-3">Cor de Destaque</label>
                                <div className="flex flex-wrap gap-3">
                                    {[
                                        { color: "#000000", name: "Preto" },
                                        { color: "#3B82F6", name: "Azul" },
                                        { color: "#EF4444", name: "Vermelho" },
                                        { color: "#10B981", name: "Verde" },
                                        { color: "#8B5CF6", name: "Roxo" },
                                        { color: "#F59E0B", name: "Laranja" },
                                    ].map((item) => (
                                        <button
                                            key={item.color}
                                            onClick={() => updateSettings("primaryColor", item.color)}
                                            className={`w-12 h-12 rounded-xl border-2 transition-all ${
                                                settings.primaryColor === item.color 
                                                    ? "border-gray-900 scale-110" 
                                                    : "border-transparent hover:scale-105"
                                            }`}
                                            style={{ backgroundColor: item.color }}
                                            title={item.name}
                                        />
                                    ))}
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Contato Tab */}
                    {activeTab === "contato" && (
                        <div className="space-y-6 animate-fade-in">
                            <h2 className="text-lg font-bold">Informa├º├Áes de Contato</h2>
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Email de Contato</label>
                                    <input 
                                        type="email" 
                                        value={settings.storeEmail}
                                        onChange={(e) => updateSettings("storeEmail", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Telefone</label>
                                    <input 
                                        type="tel" 
                                        value={settings.storePhone}
                                        onChange={(e) => updateSettings("storePhone", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1.5">Endere├ºo</label>
                                    <input 
                                        type="text" 
                                        value={settings.storeAddress}
                                        onChange={(e) => updateSettings("storeAddress", e.target.value)}
                                        className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                    />
                                </div>
                            </div>

                            <div className="pt-4 border-t">
                                <h3 className="text-sm font-bold text-gray-900 mb-4">Redes Sociais</h3>
                                <div className="space-y-3">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-pink-50 rounded-xl flex items-center justify-center text-pink-600 font-bold text-xs">IG</div>
                                        <input 
                                            type="text" 
                                            value={settings.instagram}
                                            onChange={(e) => updateSettings("instagram", e.target.value)}
                                            placeholder="https://instagram.com/dripshop"
                                            className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                        />
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600 font-bold text-xs">FB</div>
                                        <input 
                                            type="text" 
                                            value={settings.facebook}
                                            onChange={(e) => updateSettings("facebook", e.target.value)}
                                            placeholder="https://facebook.com/dripshop"
                                            className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                        />
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-black rounded-xl flex items-center justify-center text-white font-bold text-xs">X</div>
                                        <input 
                                            type="text" 
                                            value={settings.twitter}
                                            onChange={(e) => updateSettings("twitter", e.target.value)}
                                            placeholder="https://x.com/dripshop"
                                            className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl focus:outline-none focus:border-primary text-sm" 
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* Notifica├º├Áes Tab */}
                    {activeTab === "notificacoes" && (
                        <div className="space-y-6 animate-fade-in">
                            <h2 className="text-lg font-bold">Prefer├¬ncias de Notifica├º├Áes</h2>

                            <div className="space-y-3">
                                {[
                                    { key: "notifyNewOrder", label: "Novo pedido", description: "Receber notifica├º├úo quando um novo pedido for realizado" },
                                    { key: "notifyLowStock", label: "Estoque baixo", description: "Receber alerta quando um produto estiver com estoque baixo" },
                                    { key: "notifyNewCustomer", label: "Novo cliente", description: "Receber notifica├º├úo quando um novo cliente se cadastrar" },
                                ].map((item) => (
                                    <div key={item.key} className="flex items-center justify-between p-4 bg-gray-50 rounded-xl">
                                        <div>
                                            <p className="text-sm font-medium">{item.label}</p>
                                            <p className="text-xs text-gray-500">{item.description}</p>
                                        </div>
                                        <button 
                                            onClick={() => updateSettings(item.key, !settings[item.key as keyof typeof settings])}
                                            className={`w-12 h-6 rounded-full relative transition-colors ${
                                                settings[item.key as keyof typeof settings] ? 'bg-primary' : 'bg-gray-300'
                                            }`}
                                        >
                                            <span className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${
                                                settings[item.key as keyof typeof settings] ? 'right-1' : 'left-1'
                                            }`} />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

import prisma from "@/lib/db/prisma";
import { NotFoundError, ConflictError, UnauthorizedError, ValidationError } from "@/lib/errors";
import type { User, CreateUserInput, CreateAddressInput, Address } from "@/types/database";
import bcrypt from "bcryptjs";

export class UserService {
  async getUserById(id: string): Promise<User> {
    const user = await prisma.user.findUnique({
      where: { id },
      include: {
        addresses: true,
      },
    });

    if (!user) {
      throw new NotFoundError("Usu├írio");
    }

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword as User;
  }

  async getUserByEmail(email: string): Promise<User | null> {
    const user = await prisma.user.findUnique({
      where: { email },
    });

    if (!user) return null;

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword as User;
  }

  async createUser(data: CreateUserInput): Promise<User> {
    const existingUser = await prisma.user.findUnique({
      where: { email: data.email },
    });

    if (existingUser) {
      throw new ConflictError("Email j├í cadastrado");
    }

    if (data.cpf) {
      const existingCpf = await prisma.user.findUnique({
        where: { cpf: data.cpf },
      });

      if (existingCpf) {
        throw new ConflictError("CPF j├í cadastrado");
      }
    }

    const hashedPassword = await bcrypt.hash(data.password, 12);

    const user = await prisma.user.create({
      data: {
        email: data.email,
        password: hashedPassword,
        name: data.name,
        phone: data.phone,
        cpf: data.cpf,
      },
    });

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword as User;
  }

  async updateUser(
    id: string,
    data: {
      name?: string;
      phone?: string;
      cpf?: string;
    }
  ): Promise<User> {
    const user = await prisma.user.findUnique({
      where: { id },
    });

    if (!user) {
      throw new NotFoundError("Usu├írio");
    }

    if (data.cpf && data.cpf !== user.cpf) {
      const existingCpf = await prisma.user.findUnique({
        where: { cpf: data.cpf },
      });

      if (existingCpf) {
        throw new ConflictError("CPF j├í cadastrado");
      }
    }

    const updatedUser = await prisma.user.update({
      where: { id },
      data,
    });

    const { password, ...userWithoutPassword } = updatedUser;
    return userWithoutPassword as User;
  }

  async changePassword(id: string, currentPassword: string, newPassword: string): Promise<void> {
    const user = await prisma.user.findUnique({
      where: { id },
    });

    if (!user) {
      throw new NotFoundError("Usu├írio");
    }

    const isValidPassword = await bcrypt.compare(currentPassword, user.password);
    if (!isValidPassword) {
      throw new UnauthorizedError("Senha atual incorreta");
    }

    const hashedPassword = await bcrypt.hash(newPassword, 12);
    await prisma.user.update({
      where: { id },
      data: { password: hashedPassword },
    });
  }

  async validateCredentials(email: string, password: string): Promise<User> {
    const user = await prisma.user.findUnique({
      where: { email },
    });

    if (!user) {
      throw new UnauthorizedError("Email ou senha incorretos");
    }

    const isValidPassword = await bcrypt.compare(password, user.password);
    if (!isValidPassword) {
      throw new UnauthorizedError("Email ou senha incorretos");
    }

    const { password: _, ...userWithoutPassword } = user;
    return userWithoutPassword as User;
  }

  async getAddresses(userId: string): Promise<Address[]> {
    const addresses = await prisma.address.findMany({
      where: { userId },
      orderBy: { isDefault: "desc" },
    });

    return addresses as unknown as Address[];
  }

  async createAddress(userId: string, data: CreateAddressInput): Promise<Address> {
    if (data.isDefault) {
      await prisma.address.updateMany({
        where: { userId },
        data: { isDefault: false },
      });
    }

    const address = await prisma.address.create({
      data: {
        userId,
        label: data.label,
        street: data.street,
        number: data.number,
        complement: data.complement,
        neighborhood: data.neighborhood,
        city: data.city,
        state: data.state,
        zipCode: data.zipCode,
        isDefault: data.isDefault,
      },
    });

    return address as unknown as Address;
  }

  async updateAddress(
    userId: string,
    addressId: string,
    data: {
      label?: string;
      street?: string;
      number?: string;
      complement?: string;
      neighborhood?: string;
      city?: string;
      state?: string;
      zipCode?: string;
      isDefault?: boolean;
    }
  ): Promise<Address> {
    const existingAddress = await prisma.address.findFirst({
      where: {
        id: addressId,
        userId,
      },
    });

    if (!existingAddress) {
      throw new NotFoundError("Endere├ºo");
    }

    if (data.isDefault) {
      await prisma.address.updateMany({
        where: { userId, id: { not: addressId } },
        data: { isDefault: false },
      });
    }

    const address = await prisma.address.update({
      where: { id: addressId },
      data,
    });

    return address as unknown as Address;
  }

  async deleteAddress(userId: string, addressId: string): Promise<void> {
    const existingAddress = await prisma.address.findFirst({
      where: {
        id: addressId,
        userId,
      },
    });

    if (!existingAddress) {
      throw new NotFoundError("Endere├ºo");
    }

    await prisma.address.delete({
      where: { id: addressId },
    });
  }

  async getFavorites(userId: string): Promise<any[]> {
    const favorites = await prisma.favorite.findMany({
      where: { userId },
      include: {
        product: {
          include: {
            category: true,
            colors: true,
          },
        },
      },
      orderBy: { createdAt: "desc" },
    });

    return favorites.map((fav) => fav.product);
  }

  async addToFavorites(userId: string, productId: string): Promise<void> {
    const product = await prisma.product.findUnique({
      where: { id: productId },
    });

    if (!product) {
      throw new NotFoundError("Produto");
    }

    const existingFavorite = await prisma.favorite.findFirst({
      where: {
        userId,
        productId,
      },
    });

    if (existingFavorite) {
      throw new ConflictError("Produto j├í est├í nos favoritos");
    }

    await prisma.favorite.create({
      data: {
        userId,
        productId,
      },
    });
  }

  async removeFromFavorites(userId: string, productId: string): Promise<void> {
    const favorite = await prisma.favorite.findFirst({
      where: {
        userId,
        productId,
      },
    });

    if (!favorite) {
      throw new NotFoundError("Favorito");
    }

    await prisma.favorite.delete({
      where: { id: favorite.id },
    });
  }
}

export const userService = new UserService();

import type {
  User as PrismaUser,
  Product as PrismaProduct,
  Category as PrismaCategory,
  Collection as PrismaCollection,
  Creator as PrismaCreator,
  Order as PrismaOrder,
  OrderItem as PrismaOrderItem,
  CartItem as PrismaCartItem,
  Address as PrismaAddress,
} from "@prisma/client";

import { type OrderStatus, type PaymentStatus, type UserRole } from "@prisma/client";
export type { OrderStatus, PaymentStatus, UserRole };

export type { PrismaUser, PrismaProduct, PrismaCategory, PrismaCollection, PrismaCreator, PrismaOrder, PrismaOrderItem, PrismaCartItem, PrismaAddress };

export interface Product extends Omit<PrismaProduct, "categoryId" | "collectionId" | "creatorId"> {
  category: PrismaCategory | null;
  collection: PrismaCollection | null;
  creator: PrismaCreator | null;
  colors: ProductColor[];
}

export interface ProductColor {
  id?: string;
  productId?: string;
  name: string;
  hex: string;
  image?: string;
}

export interface Category extends PrismaCategory {
  subcategories?: Category[];
}

export interface Collection extends PrismaCollection { }

export interface Creator extends PrismaCreator { }

export interface User extends Omit<PrismaUser, "password"> {
  password?: string;
}

export interface Address extends PrismaAddress {
  user?: User;
}

export interface Order extends Omit<PrismaOrder, "userId" | "addressId"> {
  user: User;
  address?: Address | null;
  items: OrderItem[];
}

export interface OrderItem extends PrismaOrderItem {
  product?: Product;
}

export interface CartItem extends Omit<PrismaCartItem, "userId" | "productId"> {
  user?: User;
  product?: Product;
}

export interface CreateProductInput {
  name: string;
  description: string;
  price: number;
  originalPrice?: number;
  discount?: number;
  images: string[];
  categoryId: string;
  subcategory?: string;
  collectionId?: string;
  creatorId?: string;
  colors: { name: string; hex: string; image?: string }[];
  sizes: string[];
  stock?: number;
  isNew?: boolean;
  isFeatured?: boolean;
  isActive?: boolean;
  theme?: string;
}

export interface UpdateProductInput extends Partial<CreateProductInput> { }

export interface ProductFilters {
  category?: string;
  collection?: string;
  creator?: string;
  isNew?: boolean;
  isFeatured?: boolean;
  minPrice?: number;
  maxPrice?: number;
  search?: string;
  sortBy?: "price_asc" | "price_desc" | "newest" | "oldest" | "name_asc" | "name_desc";
  page?: number;
  limit?: number;
}

export interface PaginatedResponse<T> {
  data: T[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

export interface CreateOrderInput {
  userId: string;
  addressId?: string;
  paymentMethod: string;
  items: {
    productId: string;
    quantity: number;
    selectedSize: string;
    selectedColor: string;
  }[];
  notes?: string;
